import torch
import torch.nn as nn

torch.manual_seed(42)

# Generate sequences
def generate_data(n=500, seq_len=10):
    X, y = [], []
    for _ in range(n):
        if torch.rand(1) > 0.5:
            seq = torch.sort(torch.randn(seq_len))[0]  # increasing
            X.append(seq); y.append(1)
        else:
            seq = torch.sort(torch.randn(seq_len), descending=True)[0]  # decreasing
            X.append(seq); y.append(0)
    return torch.stack(X).unsqueeze(-1), torch.tensor(y)

